import React, { Component } from "react";

class Counter extends Component {
  constructor(props) {
    super(props);
    this.state = {
      count: 0,
    };
  }

  increment() {
    this.state.count = this.state.count + 1;
    console.log(this.state.count);
  }
  render() {
    return (
      <div>
        <div>Count - {this.state.count}</div>
        <button onClick={() => this.incremennt()}></button>
      </div>
    );
  }
}

export default App;
